import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { register } from '../services/api';  // Use named import
import '../styles/style.css';

function Register() {
  const [username, setUsername] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [role, setRole] = useState('');
  const navigate = useNavigate();

  const handleRegister = async (e) => {
    e.preventDefault();
    try {
      const response = await register({ username, email, password, role });  // Update function call
      localStorage.setItem('token', response.token);
      navigate('/complaints');  // Navigate to complaints page after registration
    } catch (err) {
      alert(err.response?.data?.message || 'Registration failed');
    }
  };

  return (
    <div className="form-container">
      <h2>Register</h2>
      <form onSubmit={handleRegister}>
        <input 
          type="text" 
          value={username} 
          onChange={(e) => setUsername(e.target.value)} 
          placeholder="Username" 
          required 
        />
        <input 
          type="email" 
          value={email} 
          onChange={(e) => setEmail(e.target.value)} 
          placeholder="Email" 
          required 
        />
        <input 
          type="password" 
          value={password} 
          onChange={(e) => setPassword(e.target.value)} 
          placeholder="Password" 
          required 
        />
        <input 
          type="text" 
          value={role} 
          onChange={(e) => setRole(e.target.value)} 
          placeholder="Role (e.g., User, Admin)" 
          required 
        />
        <button type="submit">Register</button>
      </form>
    </div>
  );
}

export default Register;
